SELECT * FROM homework


        AND id = #{id}


        AND course_id = #{courseId}


        AND title LIKE CONCAT('%', #{title}, '%')


        AND type = #{type}


        AND activity_tag = #{activityTag}


ORDER BY create_time DESC

SELECT h.id AS homeworkId, h.title AS title, c.course_name AS courseName, h.course_id AS courseId, h.deadline AS deadline, -- status 逻辑：有提交记录则用提交记录的 status，没有则默认 0（未交） CASE WHEN hs.id IS NOT NULL THEN hs.status ELSE 0 END AS status FROM homework h INNER JOIN course c ON c.id = h.course_id LEFT JOIN homework_submit hs ON hs.homework_id = h.id AND hs.student_id = #{studentId} WHERE h.course_id IN
#{cid}
-- 只展示"需要学生关注"的状态：未交(0)、已提交待批(1)、打回重做(3) AND (hs.status IS NULL OR hs.status IN (0, 1, 3)) -- 未截止或允许补交的才展示（已截止但被 forbit_late=0 允许补交的也保留） ORDER BY h.deadline ASC, h.id ASC
